"""Data processing pipeline with a performance bottleneck."""


def compute_stats(records):
    """Compute statistics across all records.
    This is expensive and shouldn't be called per-record.
    Returns dict mapping category -> {'avg': float, 'count': int, 'total': float}
    """
    stats = {}
    for rec in records:
        cat = rec.get("category", "other")
        if cat not in stats:
            stats[cat] = {"total": 0, "count": 0}
        stats[cat]["total"] += rec.get("amount", 0)
        stats[cat]["count"] += 1
    for cat in stats:
        stats[cat]["avg"] = stats[cat]["total"] / stats[cat]["count"]
    return stats


def classify_record(record, all_records):
    """Classify a single record relative to its category stats.

    BUG: Calls compute_stats on EVERY record instead of computing once.
    """
    stats = compute_stats(all_records)  # Called N times!

    cat = record.get("category", "other")
    cat_stats = stats.get(cat, {"avg": 0, "count": 0, "total": 0})
    amount = record.get("amount", 0)

    result = dict(record)
    result["category_avg"] = round(cat_stats["avg"], 2)
    result["category_count"] = cat_stats["count"]

    if amount > cat_stats["avg"] * 1.5:
        result["tier"] = "premium"
    elif amount > cat_stats["avg"]:
        result["tier"] = "above_average"
    elif amount > cat_stats["avg"] * 0.5:
        result["tier"] = "average"
    else:
        result["tier"] = "below_average"

    result["percentile"] = round(amount / cat_stats["avg"], 4) if cat_stats["avg"] > 0 else 0
    return result


def process_all(records):
    """Process all records. Returns list of classified records."""
    return [classify_record(r, records) for r in records]


def summarize(records):
    """Summarize processed records by tier count."""
    tier_counts = {}
    for r in records:
        tier = r.get("tier", "unknown")
        tier_counts[tier] = tier_counts.get(tier, 0) + 1
    return tier_counts
